from pathlib import Path
import openpyxl
import re
from datetime import datetime, date as date_type

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    ncr_files = [f for f in xlsx_files if 'ncr_log' in f.name.lower()]
    if not ncr_files:
        ncr_files = [f for f in xlsx_files if 'ncr' in f.name.lower()]
    if not ncr_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'ncr_log.xlsx not found in workspace'}

    ncr_file = ncr_files[0]
    try:
        wb = openpyxl.load_workbook(ncr_file, data_only=True)
        ws = wb.active
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not open {ncr_file.name}: {e}'}

    headers = [str(cell.value).strip() if cell.value is not None else '' for cell in ws[1]]

    def col_idx(name):
        name_norm = re.sub(r'[^a-z0-9]', '', name.lower())
        for i, h in enumerate(headers):
            if re.sub(r'[^a-z0-9]', '', h.lower()) == name_norm:
                return i
        return None

    def norm_str(val):
        if val is None:
            return ''
        return re.sub(r'[^a-z0-9]', '', str(val).lower())

    def norm_date(val):
        if val is None:
            return ''
        if isinstance(val, datetime):
            return val.strftime('%Y%m%d')
        if isinstance(val, date_type):
            return val.strftime('%Y%m%d')
        s = str(val).strip()
        m = re.match(r'^(\d{1,2})[/\-](\d{1,2})[/\-](\d{4})$', s)
        if m:
            return f'{m.group(3)}{int(m.group(1)):02d}{int(m.group(2)):02d}'
        m = re.match(r'^(\d{4})[/\-](\d{2})[/\-](\d{2})', s)
        if m:
            return f'{m.group(1)}{m.group(2)}{m.group(3)}'
        return ''

    def norm_num(val):
        if val is None:
            return None
        try:
            return float(re.sub(r'[^0-9.]', '', str(val)))
        except:
            return None

    ncr_idx = col_idx('NCR_Number')
    if ncr_idx is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'NCR_Number column not found in ncr_log.xlsx'}

    target_row = None
    for row in ws.iter_rows(min_row=2, values_only=True):
        if row[ncr_idx] is not None and str(row[ncr_idx]).strip() == 'NCR-MER-2026-0032':
            target_row = row
            break

    if target_row is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'Row NCR-MER-2026-0032 not found in ncr_log.xlsx'}

    fields = [
        ('NCR_Number',            'NCR-MER-2026-0032',                'str'),
        ('Issue_Date',            '03/12/2026',                        'date'),
        ('Supplier_ID',           'SUP-0010',                          'str'),
        ('Supplier_Name',         'Redstone Alloy Fabricators, Inc.',  'str'),
        ('PO_Number',             'MER-PO-103517',                     'str'),
        ('Receipt_ID',            'REC-20260312-001',                  'str'),
        ('SKU',                   'FL-20044-A3',                       'str'),
        ('Quantity_Affected',     80,                                   'num'),
        ('NCR_Type',              'DOC',                                'str'),
        ('Severity',              'Major',                              'str'),
        ('Dollar_Value',          3780.00,                              'num'),
        ('Status',                'Open',                               'str'),
        ('Issued_By',             'DH',                                 'str'),
        ('Supplier_Response_Due', '03/26/2026',                         'date'),
        ('Description',           None,                                 'blank'),
    ]

    errors = []
    total = len(fields)

    for col_name, expected, check_type in fields:
        idx = col_idx(col_name)
        if idx is None:
            errors.append(f'{col_name}: column not found')
            continue
        actual = target_row[idx]

        if check_type == 'str':
            if norm_str(actual) != norm_str(expected):
                errors.append(f'{col_name}: expected "{expected}", got "{actual}"')
        elif check_type == 'date':
            if norm_date(actual) != norm_date(expected):
                errors.append(f'{col_name}: expected "{expected}", got "{actual}"')
        elif check_type == 'num':
            a = norm_num(actual)
            if a is None or abs(a - expected) > 0.01:
                errors.append(f'{col_name}: expected {expected}, got "{actual}"')
        elif check_type == 'blank':
            if actual is not None and str(actual).strip() != '':
                errors.append(f'{col_name}: expected blank, got "{actual}"')

    passed = total - len(errors)
    score = round(passed / total, 4)

    if not errors:
        return {'pass': True, 'score': 1.0, 'feedback': f'All {total} fields on NCR-MER-2026-0032 verified correctly.'}

    return {
        'pass': False,
        'score': score,
        'feedback': f'{len(errors)}/{total} field(s) incorrect on NCR-MER-2026-0032:\n' + '\n'.join(f'  - {e}' for e in errors)
    }

