from pathlib import Path
import openpyxl
import re

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    recv_files = [f for f in xlsx_files if 'receiving' in f.name.lower()]
    if not recv_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'No receiving_log.xlsx file found in workspace'}

    recv_file = recv_files[0]
    try:
        wb = openpyxl.load_workbook(recv_file, data_only=True)
        ws = wb.active
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not open file: {e}'}

    # The rubric says row 10 should contain these values (pipe-delimited)
    expected_values = [
        'REC-20260309-004',
        'MER-PO-103515',
        '001',
        'FL-20044-A3',
        'N',
        'SUP-0010',
        'Reliant Freight Solutions',
        '03/09/2026 11:30 CST',
        '03/09/2026 12:15 CST',
        'Dock 3',
        '20',
        '20',
        '20',
        '0',
        '0.0%',
        'N/A',
        'Accepted',
        'Tier 0',
        'Accepted',
        'N/A',
        'Verified',
        'Accepted',
        '',
        '',
        '',
        'ACCEPTED CLEAN',
        '',
        'DH',
        'HSupplier status: Approved as of 09/14/2023. Hazmat receipt — SDS on file: FL-21300-A1_SDS.pdf. Hazmat manifest on file.',
        'Posted',
        '03/09/2026 12:30 CST',
    ]

    # Try to find the row with REC-20260309-004 (prefer row 10, but search all)
    target_row_idx = None
    for row_idx, row in enumerate(ws.iter_rows(min_row=2, values_only=False), start=2):
        for cell in row:
            if cell.value is not None and str(cell.value).strip() == 'REC-20260309-004':
                target_row_idx = row_idx
                break
        if target_row_idx:
            break

    if target_row_idx is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'Row with REC-20260309-004 not found in receiving_log.xlsx'}

    actual_row = [cell.value for cell in ws[target_row_idx]]

    def normalize(val):
        if val is None:
            return ''
        return re.sub(r'[^a-z0-9]', '', str(val).lower())

    def normalize_ts(val):
        if val is None:
            return ''
        from datetime import datetime, date as date_type
        if isinstance(val, datetime):
            return val.strftime('%Y%m%d%H%M')
        if isinstance(val, date_type):
            return val.strftime('%Y%m%d')
        s = str(val).strip()
        s = re.sub(r'\s*(cst|cdt|ct|utc|est|pst)\s*$', '', s, flags=re.IGNORECASE).strip()
        return re.sub(r'[^0-9]', '', s)

    def values_match(exp, act):
        e = str(exp).strip() if exp is not None else ''
        a = str(act).strip() if act is not None else ''

        # Both empty
        if e == '' and (act is None or a == '' or a.lower() == 'none'):
            return True

        # Normalized string match (removes punctuation, dashes, whitespace, case)
        if normalize(e) == normalize(a):
            return True

        # Timestamp comparison (strip timezone, normalize digits)
        if re.search(r'\d{2}/\d{2}/\d{4}', e):
            return normalize_ts(e) == normalize_ts(act)

        # Numeric comparison
        try:
            e_num = float(re.sub(r'[^0-9.]', '', e))
            a_num = float(re.sub(r'[^0-9.]', '', a))
            if abs(e_num - a_num) < 0.01:
                return True
        except (ValueError, AttributeError):
            pass

        return False

    errors = []
    total = len(expected_values)

    for i in range(total):
        exp = expected_values[i]
        act = actual_row[i] if i < len(actual_row) else None
        if not values_match(exp, act):
            errors.append(f'Column {i+1}: expected "{exp}", got "{actual_row[i] if i < len(actual_row) else "(missing)"}"')

    matched = total - len(errors)
    score = round(matched / total, 4)

    if not errors:
        return {'pass': True, 'score': 1.0, 'feedback': f'REC-20260309-004 found at row {target_row_idx}. All {total} fields verified correctly.'}

    return {
        'pass': False,
        'score': score,
        'feedback': f'REC-20260309-004 row validation failed ({len(errors)}/{total} fields incorrect):\n' + '\n'.join(f'  - {e}' for e in errors),
    }

