    if not slack_file.exists():
        return {'pass': False, 'score': 0.0, 'feedback': 'slack_data.json not found'}

    try:
        with open(slack_file) as f:
            data = json.load(f)
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not parse slack_data.json: {e}'}

    messages = data.get('messages', {})
    channels = data.get('channels', {})

    recv_dock_id = None
    if 'C001' in channels:
        recv_dock_id = 'C001'
    else:
        for cid, ch in channels.items():
            name = ch.get('name', '').lower()
            if 'receiving' in name and 'dock' in name:
                recv_dock_id = cid
                break
        if recv_dock_id is None:
            for cid, ch in channels.items():
                if 'dock' in ch.get('name', '').lower():
                    recv_dock_id = cid
                    break

    if recv_dock_id is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'C001 (#receiving-dock) not found in slack_data.json'}

    channel_msgs = messages.get(recv_dock_id, [])

    expected = 'TRUCK HOLD: REC-20260312-001, Redstone Alloy Fabricators, Inc., PO #MER-PO-103517. Driver on truck — hazmat documentation incomplete. Do not unload.'

    def norm(s):
        return re.sub(r'[^a-z0-9]', '', s.lower())

    expected_norm = norm(expected)

    for msg in channel_msgs:
        if norm(msg.get('text', '')) == expected_norm:
            return {'pass': True, 'score': 1.0, 'feedback': f'Found expected TRUCK HOLD message in {recv_dock_id}.'}

    # Find the closest candidate for feedback
    candidate = next((msg.get('text', '') for msg in channel_msgs if 'truck hold' in msg.get('text', '').lower()), None)
    if candidate:
        feedback = f'TRUCK HOLD message found in {recv_dock_id} but content does not match.\nExpected: "{expected}"\nFound:    "{candidate}"'
    else:
        feedback = f'No TRUCK HOLD message found in {recv_dock_id} ({len(channel_msgs)} messages present). Expected: "{expected}"'
