from pathlib import Path
import json

def verify(workspace_path, external_services_path=None):
    # We need to check slack_data.json in the external services path
    # since Slack is an external service. But also check workspace just in case.
    slack_path = None
    candidates = []

    if external_services_path:
        candidates.append(Path(external_services_path) / "slack_data.json")
    if workspace_path:
        candidates.append(Path(workspace_path) / "slack_data.json")

    for c in candidates:
        if c.exists():
            slack_path = c
            break

    if slack_path is None:
        return {"pass": False, "score": 0.0, "feedback": "Could not find slack_data.json in either external_services_path or workspace_path."}

    try:
        with open(slack_path, 'r', encoding='utf-8') as f:
            slack_data = json.load(f)
    except Exception as e:
        return {"pass": False, "score": 0.0, "feedback": f"Failed to read/parse slack_data.json: {e}"}

    forbidden_phrases = [
        "ESCALATION — DOLLAR VALUE",
        "ESCALATION - DOLLAR VALUE",   # also check with regular dash
        "ESCALATION -- DOLLAR VALUE",  # double dash variant
        "REPEAT OFFENDER FLAG",
        "SHIPMENT REFUSED"
    ]

    violations = []

    # Traverse the entire slack_data structure looking for messages
    def extract_messages(data, path=""):
        """Recursively extract all string values that could be message content."""
        texts = []
        if isinstance(data, dict):
            for key, value in data.items():
                if isinstance(value, str):
                    texts.append((f"{path}.{key}", value))
                elif isinstance(value, (dict, list)):
                    texts.extend(extract_messages(value, f"{path}.{key}"))
        elif isinstance(data, list):
            for i, item in enumerate(data):
                if isinstance(item, str):
                    texts.append((f"{path}[{i}]", item))
                elif isinstance(item, (dict, list)):
                    texts.extend(extract_messages(item, f"{path}[{i}]"))
        return texts

    all_texts = extract_messages(slack_data)

    for location, text in all_texts:
        text_upper = text.upper()
        for phrase in forbidden_phrases:
            if phrase.upper() in text_upper:
                violations.append(f"Found '{phrase}' in {location}: \"{text[:200]}\"")

    if violations:
        feedback = f"FAIL: Found {len(violations)} forbidden phrase(s) in slack_data.json:\n" + "\n".join(violations)
        return {"pass": False, "score": 0.0, "feedback": feedback}

    return {"pass": True, "score": 1.0, "feedback": "PASS: No messages in slack_data.json contain 'ESCALATION — DOLLAR VALUE', 'REPEAT OFFENDER FLAG', or 'SHIPMENT REFUSED'."}

