import openpyxl
import re
from datetime import datetime, date as date_type

def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    cpa_files = [f for f in xlsx_files if 'closed_pos' in f.name.lower() or 'closed_po' in f.name.lower()]
    if not cpa_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'closed_pos_archive.xlsx not found in workspace'}
    try:
        wb = openpyxl.load_workbook(cpa_files[0], data_only=True)
        ws = wb.active
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not open closed_pos_archive.xlsx: {e}'}

    def norm(val):
        if val is None: return ''
        return re.sub(r'[^a-z0-9]', '', str(val).lower())

    def norm_date(val):
        if val is None: return ''
        if isinstance(val, datetime): return val.strftime('%Y%m%d')
        if isinstance(val, date_type): return val.strftime('%Y%m%d')
        s = str(val).strip()
        m = re.match(r'^(\d{1,2})[/\-](\d{1,2})[/\-](\d{4})$', s)
        if m: return f'{m.group(3)}{int(m.group(1)):02d}{int(m.group(2)):02d}'
        return ''

    def norm_num(val):
        if val is None: return None
        try: return float(re.sub(r'[^0-9.]', '', str(val)))
        except: return None

    def values_match(exp, act):
        e, a = str(exp).strip(), str(act).strip() if act is not None else ''
        if norm(e) == norm(a): return True
        if re.search(r'\d{1,2}/\d{1,2}/\d{4}', e):
            return norm_date(e) == norm_date(act)
        en, an = norm_num(e), norm_num(a)
        if en is not None and an is not None:
            return abs(en - an) < 0.01
        return False

    # Updated expected rows to match the rubric:
    # Row 10: MER-PO-103515 with FL-21300-A1 (changed from FL-20044-A3)
    # Row 11: MER-PO-103516 unchanged
    expected_rows = {
        'MER-PO-103515': ['MER-PO-103515', 'SUP-0010', 'Redstone Alloy Fabricators, Inc.', '001', 'FL-21300-A1', '20', '$47.25', '03/09/2026', '03/09/2026', 'N', 'Y', '03/09/2026', 'Fulfilled', 'REC-20260309-004'],
        'MER-PO-103516': ['MER-PO-103516', 'SUP-0009', 'Gulf Coast Bearings & Seals', '001', 'BG-33044-A1', '40', '$28.50', '03/09/2026', '03/10/2026', 'Y', 'N', '03/10/2026', 'Fulfilled', 'REC-20260310-001', 'DTL delivery to LINE-ASMB-01.'],
    }

    rows_by_po = {}
    for row in ws.iter_rows(min_row=2, values_only=True):
        if row and row[0] is not None:
            rows_by_po[str(row[0]).strip()] = list(row)

    errors = []
    total = 0
    for po_num, expected_vals in expected_rows.items():
        if po_num not in rows_by_po:
            errors.append(f'{po_num}: row not found in closed_pos_archive.xlsx')
            total += len(expected_vals)
            continue
        actual = rows_by_po[po_num]
        for i, exp in enumerate(expected_vals):
            total += 1
            act = actual[i] if i < len(actual) else None
            if not values_match(exp, act):
                errors.append(f'{po_num} col {i+1}: expected "{exp}", got "{act}"')

    passed = total - len(errors)
    score = round(passed / total, 4) if total else 0.0
    if not errors:
        return {'pass': True, 'score': 1.0, 'feedback': f'All {total} fields verified across both rows.'}
    return {'pass': False, 'score': score, 'feedback': f'{len(errors)}/{total} field(s) incorrect:\n' + '\n'.join(f'  - {e}' for e in errors)}

