def verify(workspace_path, external_services_path=None):
    xlsx_files = list(Path(workspace_path).glob('**/*.xlsx'))
    recv_files = [f for f in xlsx_files if 'receiving' in f.name.lower()]
    if not recv_files:
        return {'pass': False, 'score': 0.0, 'feedback': 'receiving_log.xlsx not found in workspace'}
    try:
        wb = openpyxl.load_workbook(recv_files[0], data_only=True)
        ws = wb.active
    except Exception as e:
        return {'pass': False, 'score': 0.0, 'feedback': f'Could not open receiving_log.xlsx: {e}'}

    headers = {}
    for col_idx, cell in enumerate(ws[1], start=1):
        if cell.value is not None:
            headers[str(cell.value).strip()] = col_idx

    def norm(val):
        if val is None: return ''
        return re.sub(r'[^a-z0-9]', '', str(val).lower())

    def norm_ts(val):
        if val is None: return ''
        if isinstance(val, (datetime, date_type)):
            return val.strftime('%m%d%Y%H%M') if isinstance(val, datetime) else val.strftime('%m%d%Y')
        s = re.sub(r'[^a-z0-9]', '', str(val).lower())
        s = re.sub(r'(cst|cdt|est|pst|mst|ct|utc)$', '', s)
        return s

    def get(row, col_name):
        if col_name not in headers: return None
        return ws.cell(row=row, column=headers[col_name]).value

    def is_blank(val):
        return val is None or str(val).strip() == ''

    # Find row by Receipt_ID
    receipt_id_col = headers.get('Receipt_ID')
    target_row = None
    if receipt_id_col:
        for row_idx in range(2, ws.max_row + 1):
            if norm(ws.cell(row=row_idx, column=receipt_id_col).value) == norm('REC-20260312-001'):
                target_row = row_idx
                break
    if target_row is None:
        return {'pass': False, 'score': 0.0, 'feedback': 'Row REC-20260312-001 not found in receiving_log.xlsx'}

    expected_values = {
        'Receipt_ID':          ('REC-20260312-001',       'str'),
        'PO_Number':           ('MER-PO-103517',           'str'),
        'Supplier_ID':         ('SUP-0010',                'str'),
        'Carrier_Name':        ('Reliant Freight Solutions','str'),
        'Arrival_Timestamp':   ('031220261015',             'ts'),
        'Dock_Door':           ('Dock 2',                  'str'),
        'Coordinator_Initials':('DH',                      'str'),
        'Status':              ('In Process',              'str'),
    }

    expected_blank = [
        'PO_Line', 'SKU', 'Safety_Critical', 'Disposition_Timestamp',
        'Qty_Ordered', 'Qty_Claimed_On_Slip', 'Qty_Received',
        'Variance_Units', 'Variance_Pct', 'Variance_Band',
        'Quantity_Action', 'Condition_Tier', 'Condition_Action',
        'Photos_Folder', 'Documentation_Status', 'Documentation_Action',
        'Heat_Numbers', 'COC_Filename', 'MTR_Filename',
        'Disposition', 'Notes', 'Putaway_Authorized_Timestamp',
    ]

    errors = []
    total = len(expected_values) + len(expected_blank)

    for col_name, (expected, check_type) in expected_values.items():
        if col_name not in headers:
            errors.append(f'{col_name}: column not found')
            continue
        actual = get(target_row, col_name)
        if check_type == 'str':
            if norm(actual) != norm(expected):
                errors.append(f'{col_name}: expected "{expected}", got "{actual}"')
        elif check_type == 'ts':
            if norm_ts(actual) != expected:
                errors.append(f'{col_name}: expected "03/12/2026 10:15 CST", got "{actual}"')

    for col_name in expected_blank:
        if col_name not in headers:
            total -= 1
            continue
        actual = get(target_row, col_name)
        if not is_blank(actual):
            errors.append(f'{col_name}: expected blank, got "{actual}"')

    passed = total - len(errors)
    score = round(passed / total, 4) if total else 0.0
    if not errors:
        return {'pass': True, 'score': 1.0, 'feedback': f'All {total} checks passed for REC-20260312-001.'}
    return {'pass': False, 'score': score, 'feedback': f'{len(errors)}/{total} check(s) failed for REC-20260312-001:\n' + '\n'.join(f'  - {e}' for e in errors)}

